// node_conv_230 -- pointwise 1x1 conv2d, tiled-streaming contract.
//   IC=128, OC=512, IH=IW=OH=OW=28, stride=1, padding=0.
//   MP=4, channel_tile=32 -> IN_BEATS=4, OUT_BEATS=16.
//   K_TOTAL=128, OC_PASSES=128.
//   Latency = IN_BEATS + OC_PASSES*(MP*K_TOTAL + 6) = 4 + 128*518 = 66308.
//
// Architecture: 3-stage MAC pipeline
//   addr -> weight_q -> mul_q -> indexed accumulator
// Per OC pass: 512 issues + 3 drain + ST_BIAS + ST_SCALE + ST_OUTPUT = 518.
// Full-OC staging buffer out_pack -- only valid_out after the final OC pass
// completes; then OUT_BEATS=16 beats stream from out_pack on consecutive cycles.
// valid_out stays HIGH for ALL OUT_BEATS beats including the last (dropped one
// cycle later in ST_LOAD) so the testbench captures every beat.
//
// Array writes (acc/biased/scaled) live in a sync-only always block to avoid
// the activation_memory_in_async_reset_block preflight rule.

module node_conv_230 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);

    localparam IC            = 128;
    localparam OC            = 512;
    localparam IH            = 28;
    localparam IW            = 28;
    localparam OH            = 28;
    localparam OW            = 28;
    localparam KH            = 1;
    localparam KW            = 1;
    localparam K_TOTAL       = IC*KH*KW;
    localparam MP            = 4;
    localparam OC_PASSES     = (OC + MP - 1) / MP;
    localparam CHANNEL_TILE  = 32;
    localparam IN_BEATS      = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam OUT_BEATS     = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam TILE_BITS     = CHANNEL_TILE * 8;
    localparam TOTAL_PIXELS  = OH * OW;

    localparam integer SCALE_SHIFT = 21;
    localparam signed [15:0] SCALE_MULT_CONST = 16'sd23595;

    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = 24;
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = 33;
    localparam integer SCALE_CONST_W = 16;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;

    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    (* rom_style = "block", ram_style = "block" *)
    reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *)
    reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_230_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_230_bias.hex",    biases);
    end

    reg [IC*8-1:0]              in_latch;
    reg [OC*8-1:0]              out_pack;
    reg [4:0]                   pixel_row;
    reg [4:0]                   pixel_col;
    reg [1:0]                   in_beat_idx;
    reg [4:0]                   out_beat_idx;
    reg [9:0]                   active_emit_count;
    reg [6:0]                   oc_group;
    reg [1:0]                   lane_counter;
    reg [7:0]                   k_counter;

    reg signed [7:0]                          weight_q;
    reg signed [7:0]                          in_byte_q;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;
    reg [1:0]                                 mac_lane_q1, mac_lane_q2;
    reg                                       mac_valid_q1, mac_valid_q2;
    reg                                       mac_done_issuing;
    reg [2:0]                                 drain_count;
    reg                                       acc_clr;

    reg signed [ACC_W-1:0]      acc    [0:MP-1];
    reg signed [BIASED_W-1:0]   biased [0:MP-1];
    reg signed [SCALED_W-1:0]   scaled [0:MP-1];
    reg signed [SCALED_W-1:0]   v_tmp;

    integer lane_i;
    integer global_oc;
    reg [15:0] weight_addr;

    localparam [2:0] ST_LOAD    = 3'd0;
    localparam [2:0] ST_RUNNING = 3'd1;
    localparam [2:0] ST_BIAS    = 3'd2;
    localparam [2:0] ST_SCALE   = 3'd3;
    localparam [2:0] ST_OUTPUT  = 3'd4;
    localparam [2:0] ST_EMIT    = 3'd5;
    reg [2:0] state;

    always @* begin
        weight_addr = (oc_group*MP + lane_counter)*K_TOTAL + k_counter;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state             <= ST_LOAD;
            ready_in          <= 1'b1;
            valid_out         <= 1'b0;
            data_out          <= {TILE_BITS{1'b0}};
            in_latch          <= {(IC*8){1'b0}};
            out_pack          <= {(OC*8){1'b0}};
            pixel_row         <= 5'd0;
            pixel_col         <= 5'd0;
            in_beat_idx       <= 2'd0;
            out_beat_idx      <= 5'd0;
            active_emit_count <= 10'd0;
            oc_group          <= 7'd0;
            lane_counter      <= 2'd0;
            k_counter         <= 8'd0;
            weight_q          <= 8'sd0;
            in_byte_q         <= 8'sd0;
            mul_q             <= {PROD_W{1'b0}};
            mac_lane_q1       <= 2'd0;
            mac_lane_q2       <= 2'd0;
            mac_valid_q1      <= 1'b0;
            mac_valid_q2      <= 1'b0;
            mac_done_issuing  <= 1'b0;
            drain_count       <= 3'd0;
            acc_clr           <= 1'b0;
        end else begin
            acc_clr <= 1'b0;

            mul_q        <= weight_q * in_byte_q;
            mac_lane_q2  <= mac_lane_q1;
            mac_valid_q2 <= mac_valid_q1;

            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        in_latch[in_beat_idx*TILE_BITS +: TILE_BITS] <= data_in;
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx      <= 2'd0;
                            ready_in         <= 1'b0;
                            state            <= ST_RUNNING;
                            oc_group         <= 7'd0;
                            lane_counter     <= 2'd0;
                            k_counter        <= 8'd0;
                            mac_done_issuing <= 1'b0;
                            mac_valid_q1     <= 1'b0;
                            drain_count      <= 3'd0;
                            acc_clr          <= 1'b1;
                        end else begin
                            in_beat_idx <= in_beat_idx + 2'd1;
                        end
                    end
                end

                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        weight_q     <= weights[weight_addr];
                        in_byte_q    <= $signed(in_latch[k_counter*8 +: 8]);
                        mac_lane_q1  <= lane_counter;
                        mac_valid_q1 <= 1'b1;

                        if (k_counter == K_TOTAL - 1) begin
                            k_counter <= 8'd0;
                            if (lane_counter == MP - 1) begin
                                mac_done_issuing <= 1'b1;
                            end else begin
                                lane_counter <= lane_counter + 2'd1;
                            end
                        end else begin
                            k_counter <= k_counter + 8'd1;
                        end
                    end else begin
                        mac_valid_q1 <= 1'b0;
                        drain_count  <= drain_count + 3'd1;
                        if (drain_count == 3'd2) begin
                            state <= ST_BIAS;
                        end
                    end
                end

                ST_BIAS: begin
                    state <= ST_SCALE;
                end

                ST_SCALE: begin
                    state <= ST_OUTPUT;
                end

                ST_OUTPUT: begin
                    for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1) begin
                        v_tmp = (scaled[lane_i] +
                                 (scaled[lane_i][SCALED_W-1] ? SCALE_ROUND_HALF_M1
                                                             : SCALE_ROUND_HALF)
                                ) >>> SCALE_SHIFT;
                        global_oc = oc_group*MP + lane_i;
                        out_pack[global_oc*8 +: 8] <=
                            (v_tmp >  49'sd127)  ?  8'sd127 :
                            (v_tmp < -49'sd128) ? -8'sd128 :
                                                   v_tmp[7:0];
                    end

                    if (oc_group == OC_PASSES - 1) begin
                        valid_out    <= 1'b1;
                        data_out     <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 5'd1;
                        state        <= ST_EMIT;
                    end else begin
                        oc_group         <= oc_group + 7'd1;
                        lane_counter     <= 2'd0;
                        k_counter        <= 8'd0;
                        mac_done_issuing <= 1'b0;
                        mac_valid_q1     <= 1'b0;
                        drain_count      <= 3'd0;
                        state            <= ST_RUNNING;
                        acc_clr          <= 1'b1;
                    end
                end

                ST_EMIT: begin
                    data_out  <= out_pack[out_beat_idx*TILE_BITS +: TILE_BITS];
                    valid_out <= 1'b1;
                    if (out_beat_idx == OUT_BEATS - 1) begin
                        out_beat_idx <= 5'd0;
                        state        <= ST_LOAD;
                        ready_in     <= 1'b1;
                        if (active_emit_count == TOTAL_PIXELS - 1) begin
                            active_emit_count <= 10'd0;
                            pixel_row         <= 5'd0;
                            pixel_col         <= 5'd0;
                        end else begin
                            active_emit_count <= active_emit_count + 10'd1;
                            if (pixel_col == IW - 1) begin
                                pixel_col <= 5'd0;
                                pixel_row <= pixel_row + 5'd1;
                            end else begin
                                pixel_col <= pixel_col + 5'd1;
                            end
                        end
                    end else begin
                        out_beat_idx <= out_beat_idx + 5'd1;
                    end
                end

                default: state <= ST_LOAD;
            endcase
        end
    end

    always @(posedge clk) begin
        if (acc_clr) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1)
                acc[lane_i] <= {ACC_W{1'b0}};
        end else if (mac_valid_q2) begin
            acc[mac_lane_q2] <= acc[mac_lane_q2] + mul_q;
        end

        if (state == ST_BIAS) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1)
                biased[lane_i] <= acc[lane_i] + biases[oc_group*MP + lane_i];
        end

        if (state == ST_SCALE) begin
            for (lane_i = 0; lane_i < MP; lane_i = lane_i + 1)
                scaled[lane_i] <= biased[lane_i] * SCALE_MULT_CONST;
        end
    end

endmodule
